def calculate_correction(original_correction: int, age: int) -> int:
    """
    根据年龄计算校正后的条文校正数
    规则：
    1. 1-10岁/81-108岁：校正数+2（>6则-6）
    2. 其他年龄：校正数+3（>20则-20）
    """
    if original_correction == 0:
        return 0
    if (1 <= age <= 10) or (81 <= age <= 108):
        new_correction = original_correction + 2
        if new_correction > 6:
            new_correction -= 6
    else:
        new_correction = original_correction + 3
        if new_correction > 20:
            new_correction -= 20
    return new_correction


def get_hexagram_by_benming(benming_num: int) -> str:
    """根据本命数查卦名"""
    return HEXAGRAM_MAP.get(benming_num, "")


def get_benming_tiaowen(hexagram: str, xiantian: int, moment: str) -> dict:
    """
    获取本命条文编号

    Args:
        hexagram: 辟卦名
        xiantian: 先天命数
        moment: 考刻（初刻/正刻）
    Returns:
        dict with keys: xingge, caiqian, caiyun, xiongdi (条文编号列表)
    """
    for item in BENMING_DATA:
        if item["hexagram"] != hexagram:
            continue
        # 匹配先天命数
        if moment == "初刻":
            match_nums = [int(x) for x in item["xiantian_chu"].split(",") if x.strip().isdigit()]
        else:
            match_nums = [int(x) for x in item["xiantian_zheng"].split(",") if x.strip().isdigit()]
        if xiantian in match_nums:
            # 解析条文编号（可能有多个，用换行分隔）
            def parse_nums(s):
                return [int(x) for x in s.replace("\n", " ").split() if x.strip().isdigit()]
            return {
                "xingge": parse_nums(item["xingge"]),
                "caiqian": parse_nums(item["caiqian"]),
                "caiyun": parse_nums(item["caiyun"]),
                "xiongdi": parse_nums(item["xiongdi"]),
            }
    return {}


